public int[][] construct2DArray(int[] original, int m, int n) {
    if (m * n != original.length) return new int[][]{};
    int[][] res = new int[m][n];
    for (int i = 0; i < original.length; ++i) {
        res[i / n][i % n] = original[i];
    }
    return res;
}
```

